// ── COMBATANTS HELPER ─────────────────────────────────────
export function translateCombatants(lang: Lang, str: string): string {
  if (lang !== 'en') return str
  let result = str
  // Sort longest first to prevent partial matches overriding full phrases
  const entries = Object.entries(COUNTRY_EN).sort((a, b) => b[0].length - a[0].length)
  for (const [es, en] of entries) {
    if (result.includes(es)) {
      result = result.split(es).join(en)
    }
  }
  return result
}

// ── YEAR TRANSLATION ──────────────────────────────────────
export function translateYear(lang: Lang, year: string): string {
  if (lang !== 'en') return year
  return year
    .replace(/\bEne\b/g, 'Jan').replace(/\bFeb\b/g, 'Feb').replace(/\bMar\b/g, 'Mar')
    .replace(/\bAbr\b/g, 'Apr').replace(/\bMayo\b/gi, 'May').replace(/\bJun\b/g, 'Jun')
    .replace(/\bJul\b/g, 'Jul').replace(/\bAgo\b/g, 'Aug').replace(/\bSep\b/g, 'Sep')
    .replace(/\bOct\b/g, 'Oct').replace(/\bNov\b/g, 'Nov').replace(/\bDic\b/g, 'Dec')
    .replace(/\ba\.C\./g, 'BC').replace(/\bd\.C\./g, 'AD')
    .replace(/\bc\.\s*/g, 'c. ')
}

// ── ERA OVERVIEW HELPER ────────────────────────────────────
export function getEraOverview(lang: Lang, eraId: EraId, spanishOverview: string): string {
  if (lang === 'en') return ERA_OVERVIEWS_EN[eraId] ?? spanishOverview
  return spanishOverview
}
